command:
ssh -i /home/jose/.ssh/n8n_bridge -o StrictHostKeyChecking=no jose@192.168.0.202 "cat > /tmp/check_hermes.sh << 'SHEOF'
echo === SYSTEMD SYSTEM ===
ls /etc/systemd/system/hermes* 2>/dev/null || echo none
echo === SYSTEMD USER ===
ls /home/jose/.config/systemd/user/hermes* 2>/dev/null || echo none
echo === BINARY ===
which hermes 2>/dev/null || echo not_in_path
ls /usr/local/bin/hermes 2>/dev/null || echo not_local_bin
ls /home/jose/.npm-global/bin/hermes 2>/dev/null || echo not_npm
echo === HERMES DIR ===
ls /home/jose/.hermes/
SHEOF
bash /tmp/check_hermes.sh"
